#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=2e5+5;
int a[maxn],dp[maxn],q[maxn];
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,k;
	cin>>n>>k;
	int tot=0;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		tot+=a[i];
	}
	int h=1,t=0;
	q[++t]=0;
	for(int i=1;i<=n+1;i++){
		while(h<=t&&q[h]<i-k-1){
			h++;
		}
		dp[i]=dp[q[h]]+a[i];
		while(h<=t&&dp[q[t]]>=dp[i]){
			t--;
		}
		q[++t]=i;
	}
	cout<<tot-dp[n+1];
	return 0;
}
